starterCss:
/* Optimize: This animation causes layout thrash.
   Replace width/height/top/left changes with
   transform and opacity for GPU-accelerated rendering. */
.perf-demo {
  position: relative;
  height: 200px;
  background: #f0f0f0;
  overflow: hidden;
}
.animated-box {
  position: absolute;
  width: 100px;
  height: 60px;
  background-color: #007bff;
  color: white;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 12px;
  border-radius: 4px;
  top: 70px;
  left: 0;
  /* BAD: animating layout properties */
  animation: slide-bad 2s ease-in-out infinite alternate;
}
@keyframes slide-bad {
  from {
    left: 0;
    width: 100px;
  }
  to {
    left: calc(100% - 140px);
    width: 140px;
  }
}

