.perf-demo {
  position: relative;
  height: 200px;
  background: #f0f0f0;
  overflow: hidden;
}
.animated-box {
  position: absolute;
  width: 100px;
  height: 60px;
  background-color: rgb(0, 123, 255);
  color: white;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 12px;
  border-radius: 4px;
  top: 70px;
  left: 0;
  will-change: transform;
  animation: slide-good 2s ease-in-out infinite alternate;
}
@keyframes slide-good {
  from {
    transform: translateX(0) scaleX(1);
  }
  to {
    transform: translateX(calc(100cqw - 140px)) scaleX(1.4);
  }
}

